/**
 * theme.min.js (pengganti minimal)
 * File asli dari template Duralux/NXL tidak tersedia di project ini.
 * File ini berisi inisialisasi dasar agar komponen Bootstrap (dropdown, dll)
 * dan toggle sidebar tetap berfungsi.
 */
(function () {
    "use strict";

    document.addEventListener("DOMContentLoaded", function () {

        // Inisialisasi semua dropdown Bootstrap yang ada di halaman
        if (typeof bootstrap !== "undefined" && bootstrap.Dropdown) {
            var dropdownElList = document.querySelectorAll('[data-bs-toggle="dropdown"]');
            dropdownElList.forEach(function (el) {
                try {
                    bootstrap.Dropdown.getOrCreateInstance(el);
                } catch (e) {
                    console.warn("Gagal inisialisasi dropdown:", el, e);
                }
            });
        }

        // Fallback manual khusus avatar user, kalau Bootstrap dropdown
        // gagal ter-trigger lewat data-attribute (mis. konflik versi)
        var userToggle = document.getElementById("userDropdownToggle");
        if (userToggle) {
            userToggle.addEventListener("click", function (e) {
                e.preventDefault();
                e.stopPropagation();

                var menu = userToggle.nextElementSibling;
                if (!menu) return;

                var isOpen = menu.classList.contains("show");

                // Tutup dropdown lain yang mungkin terbuka
                document.querySelectorAll(".dropdown-menu.show").forEach(function (m) {
                    m.classList.remove("show");
                });

                if (!isOpen) {
                    menu.classList.add("show");
                }
            });

            // Tutup dropdown saat klik di luar area
            document.addEventListener("click", function (e) {
                if (!userToggle.contains(e.target)) {
                    var menu = userToggle.nextElementSibling;
                    if (menu) menu.classList.remove("show");
                }
            });
        }

        // Toggle sidebar mini (menu-mini-button & menu-expend-button)
        var miniBtn = document.getElementById("menu-mini-button");
        var expendBtn = document.getElementById("menu-expend-button");

        if (miniBtn && expendBtn) {
            miniBtn.addEventListener("click", function () {
                document.body.classList.add("nxl-menu-mini");
                miniBtn.style.display = "none";
                expendBtn.style.display = "inline-block";
            });

            expendBtn.addEventListener("click", function () {
                document.body.classList.remove("nxl-menu-mini");
                expendBtn.style.display = "none";
                miniBtn.style.display = "inline-block";
            });
        }

        // Toggle sidebar di mobile
        var mobileToggler = document.getElementById("mobile-collapse");
        if (mobileToggler) {
            mobileToggler.addEventListener("click", function () {
                document.body.classList.toggle("nxl-sidebar-open");
            });
        }

    });
})();
